using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// --- Set up options with a known type (Person) ---
var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver(),
    PropertyNamingPolicy = JsonNamingPolicy.CamelCase
};

// 1️⃣  Strongly-typed metadata: GetTypeInfo<T>() → JsonTypeInfo<T>
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Got JsonTypeInfo<Person>  – type handled: {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Ada", 36), personInfo);
Console.WriteLine($"Serialized with typed info: {json}");

Person roundTripped = JsonSerializer.Deserialize(json, personInfo)!;
Console.WriteLine($"Deserialized back:         {roundTripped}");

// 2️⃣  Probe without throwing: TryGetTypeInfo()
//     DefaultJsonTypeInfoResolver can resolve any type, so both succeed here.
//     To show a "not found" path we use a custom resolver that only knows Person.
var limitedOptions = new JsonSerializerOptions
{
    TypeInfoResolver = new PersonOnlyResolver()
};

if (limitedOptions.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? found))
    Console.WriteLine($"\n✅ Person metadata found   – {found!.Type.Name}");
else
    Console.WriteLine("\n❌ Person metadata NOT found");

if (limitedOptions.TryGetTypeInfo(typeof(Order), out JsonTypeInfo? missing))
    Console.WriteLine($"✅ Order metadata found    – {missing!.Type.Name}");
else
    Console.WriteLine("❌ Order metadata NOT found (no exception thrown!)");

// --- Types ---
record Person(string Name, int Age);
record Order(int Id, decimal Total);

// --- A resolver that only knows about Person ---
sealed class PersonOnlyResolver : IJsonTypeInfoResolver
{
    private readonly DefaultJsonTypeInfoResolver _inner = new();

    public JsonTypeInfo? GetTypeInfo(Type type, JsonSerializerOptions options)
        => type == typeof(Person) ? _inner.GetTypeInfo(type, options) : null;
}

